!function(){"use strict";window.ImageEditor.prototype.initializeTipSection=function(){const t=["Tip: use arrows to move a selected object by 1 pixel!","Tip: Shift + Click to select and modify multiple objects!","Tip: hold Shift when rotating an object for 15° angle jumps!","Tip: hold Shift when drawing a line for 15° angle jumps!","Tip: Ctrl +/-, Ctrl + wheel to zoom in and zoom out!"],n=this;$(this.containerSelector+" .canvas-holder .content").append(`\n    <div id="tip-container">${t[parseInt(Math.random()*t.length)]}</div>`),this.hideTip=function(){$(n.containerSelector+" .canvas-holder .content #tip-container").hide()},this.showTip=function(){$(n.containerSelector+" .canvas-holder .content #tip-container").show()},this.updateTip=function(t){"string"==typeof t&&$(n.containerSelector+" .canvas-holder .content #tip-container").html(t)}}}();